section.code:
{
  "central_claim": "Acme cut report-generation time from 4 days to 30 minutes by replacing manual SQL exports with the analytics platform.",
  "body": {
    "once": "Acme's analytics team manually ran weekly SQL exports.",
    "every_day": "Every Friday morning the senior analyst spent 4 days assembling the leadership report.",
    "one_day": "One Friday the report missed the board meeting; revenue questions went unanswered.",
    "bot1": "Because of that, the CFO mandated an alternative within 2 weeks.",
    "bot2": "Because of that, they evaluated 3 tools and picked Acme's platform.",
    "until": "Until finally, the same report ran in 30 minutes \u2014 and the analyst moved to higher-leverage work."
  }
}
